import{c as e,Q as o,j as a,m as r}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"Feature Request: Lazy Loading for MCP Servers and Tools (#7336)","description":"","frontmatter":{"url":"https://github.com/anthropics/claude-code/issues/7336","date":"2026-05-12T00:00:00.000Z","scored":"2026-05-16T00:00:00.000Z","source":"GitHub Issues — anthropics/claude-code","source_file":"../2026-05-12-github-7336-mcp-lazy-loading.md","source_tier":"C","tags":["mcp","lazy-loading","token-overhead","context-management","feature-request"]},"headers":[],"relativePath":"research/ai-articles/scored/2026-05-12-github-7336-mcp-lazy-loading.md","filePath":"research/ai-articles/scored/2026-05-12-github-7336-mcp-lazy-loading.md","lastUpdated":1779894392000}'),d={name:"research/ai-articles/scored/2026-05-12-github-7336-mcp-lazy-loading.md"};function s(n,t,l,i,c,h){return o(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="feature-request-lazy-loading-for-mcp-servers-and-tools-7336" tabindex="-1">Feature Request: Lazy Loading for MCP Servers and Tools (#7336) <a class="header-anchor" href="#feature-request-lazy-loading-for-mcp-servers-and-tools-7336" aria-label="Permalink to &quot;Feature Request: Lazy Loading for MCP Servers and Tools (#7336)&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://github.com/anthropics/claude-code/issues/7336" target="_blank" rel="noreferrer">https://github.com/anthropics/claude-code/issues/7336</a><br><strong>狀態</strong>：Feature request（尚未實作）</p><hr><h2 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h2><p>量化了 MCP tool schema 的真實 token 成本：一個有 73 個 MCP tool 的環境，啟動時消耗 108k tokens（54% of 200k limit），僅剩 92k 可用。提出 lazy loading 方案（registry index ~5k tokens，按需載入），並有 PoC 實作。對 context-management 規則有直接補充價值。</p><hr><h2 id="核心數據-量化-token-成本" tabindex="-1">核心數據（量化 token 成本） <a class="header-anchor" href="#核心數據-量化-token-成本" aria-label="Permalink to &quot;核心數據（量化 token 成本）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>組件</th><th>Token 成本</th><th>佔比</th></tr></thead><tbody><tr><td>MCP tools（73 個）</td><td>39,800t</td><td>19.9%</td></tr><tr><td>Custom agents（56 個）</td><td>9,700t</td><td>4.9%</td></tr><tr><td>System tools</td><td>22,600t</td><td>11.3%</td></tr><tr><td>Memory files</td><td>36,000t</td><td>18.0%</td></tr><tr><td><strong>合計</strong></td><td><strong>~108,000t</strong></td><td><strong>54%</strong></td></tr></tbody></table><p>可用 context：<strong>92k tokens</strong>（46%）</p><p>Lazy loading 後預估：<strong>195k tokens 可用</strong>（5k registry + 按需載入）</p><hr><h2 id="核心提案" tabindex="-1">核心提案 <a class="header-anchor" href="#核心提案" aria-label="Permalink to &quot;核心提案&quot;">​</a></h2><ul><li><strong>Registry index</strong>：只載入 name + description + trigger keywords（~5k tokens）</li><li><strong>On-demand loading</strong>：偵測 user input keywords → 載入相關工具</li><li><strong>Session cache</strong>：已載入的工具 cache 整個 session</li></ul><hr><h2 id="cc-workspace-可行動性" tabindex="-1">cc-workspace 可行動性 <a class="header-anchor" href="#cc-workspace-可行動性" aria-label="Permalink to &quot;cc-workspace 可行動性&quot;">​</a></h2><ol><li><code>context-management.md</code> § Token Overhead 表格標記「MCP tool schemas 6%」——此 issue 提供精確的每工具 token 成本（平均 ~544t/tool）和具體量化數據</li><li>在官方實作 lazy loading 前，可手動緩解： <ul><li>減少 MCP server 數量（只配置當前任務需要的）</li><li>確認 MCP tool schemas 確實是瓶頸再配置</li></ul></li></ol><hr><h2 id="評分" tabindex="-1">評分 <a class="header-anchor" href="#評分" aria-label="Permalink to &quot;評分&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>7/10</td><td>提供 MCP token 成本的精確量化數據，可補充 context-management.md；lazy loading 尚未實作，短期只能手動緩解</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>量化「每個工具 ~544t」的具體數字是新數據；lazy loading 概念在 IDE 生態有先例（VSCode、JetBrains）</td></tr><tr><td>C. 證據品質</td><td>6/10</td><td>真實環境量測數據（單一用戶）+ PoC；非廣泛驗證，但數據點本身可信</td></tr><tr><td>D. 技術深度</td><td>6/10</td><td>包含 JSON 配置範例、三階段實作計畫；PoC 存在但未附完整代碼</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>MCP token 成本問題適用所有重度 MCP 用戶</td></tr><tr><td><strong>加權總分</strong></td><td><strong>6.8/10</strong></td><td>7×0.3 + 7×0.2 + 6×0.2 + 6×0.15 + 8×0.15 = 2.10+1.40+1.20+0.90+1.20</td></tr></tbody></table><p><strong>整合決策</strong>：Rule（補充量化數據到現有 context-management 規則）<br><strong>整合位置</strong>：<code>.claude/rules/context-management.md</code> § Token Overhead 九大模式表格 — MCP tool schemas 行補充「平均 ~544t/tool，73 tools = 39.8k tokens」具體量化<br><strong>整合狀態</strong>：待實作</p><hr><h2 id="todo" tabindex="-1">TODO <a class="header-anchor" href="#todo" aria-label="Permalink to &quot;TODO&quot;">​</a></h2><ul><li>[ ] 更新 <code>context-management.md</code> § Token Overhead 表格，MCP tool schemas 欄位補充具體量化（39.8k tokens for 73 tools）</li><li>[ ] 追蹤 GitHub issue #7336 狀態，官方實作後更新 workspace 配置建議</li></ul>',23)])])}const m=e(d,[["render",s]]);export{u as __pageData,m as default};
